define i8 @dont_negate_ordinary_select(i8 %x, i8 %y, i8 %z, i1 %c) {
; CHECK-LABEL: define i8 @dont_negate_ordinary_select(
; CHECK-SAME: i8 [[X:%.*]], i8 [[Y:%.*]], i8 [[Z:%.*]], i1 [[C:%.*]]) {
; CHECK-NEXT:    [[T0:%.*]] = select i1 [[C]], i8 [[X]], i8 [[Y]]
; CHECK-NEXT:    [[T1:%.*]] = sub i8 [[Z]], [[T0]]
; CHECK-NEXT:    ret i8 [[T1]]
  %t0 = select i1 %c, i8 %x, i8 %y
  %t1 = sub i8 %z, %t0
  ret i8 %t1
}

tests.source_program:
define i8 @dont_negate_ordinary_select(i8 %x, i8 %y, i8 %z, i1 %c) {
  %t0 = select i1 %c, i8 %x, i8 %y
  %t1 = sub i8 %z, %t0
  ret i8 %t1
}

define i4 @negate_freeze(i4 %x, i4 %y, i4 %z) {
  %t0 = sub i4 %x, %y
  %t1 = freeze i4 %t0
  %t2 = sub i4 %z, %t1
  ret i4 %t2
}

define i4 @negate_freeze(i4 %x, i4 %y, i4 %z) {
  %t0 = sub i4 %x, %y
  %t1 = freeze i4 %t0
  %t2 = sub i4 %z, %t1
  ret i4 %t2
}

define <2 x i32> @negate_select_of_negation_poison(<2 x i1> %c, <2 x i32> %x) {
  %neg = sub <2 x i32> <i32 0, i32 poison>, %x
  %sel = select <2 x i1> %c, <2 x i32> %neg, <2 x i32> %x
  %neg2 = sub <2 x i32> zeroinitializer, %sel
  ret <2 x i32> %neg2
}

define i8 @urem_without_assume(i8 %arg, i8 %arg2) {
  %x = urem i8 %arg, %arg2
  %add = add i8 %x, 1
  %out = urem i8 %add, %arg2
  ret i8 %out
}
